  ('aboriginal-7c9828ae-moex-00108', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '關於行政法法源之敘述，下列何者錯誤？', '["關於法源位階，憲法高於法律，法律高於命令", "行政法之法源，得分為成文法源以及不成文法源", "國際法於符合一定條件下，亦得成為行政法之法源", "涉及兩岸之協定，礙於政治因素皆不得成為行政法之法源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00109', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '下列何者非屬行政法之一般法律原則？', '["明確性原則", "契約自由原則", "比例原則", "信賴保護原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00110', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '依最高行政法院實務見解，關於公立高中與其教師間法律關係之敘述，下列何者正確？', '["公立高中與其教師間之關係為公務人員任用之法律關係", "公立高中對其教師所為之年終考核，為基於契約關係所為之意思表示", "主管機關依法對所屬公立高中教師所為之平時考核獎懲，為非屬行政處分之內部管理措施", "公立高中教師不服學校對其所為之申誡懲處者，得以學校為被告，依法向行政法院提起撤銷訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00111', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '關於行政組織態樣之敘述，下列何者錯誤？', '["行政機關為防止人民違法棄置廢棄物而請求警察協助，學理上稱為行政助手", "行政機關授予機車行檢驗廢氣排放權限，學理上稱為委託私人行使公權力", "依法律獨立行使其專業權限並不受政治影響所創設之組織，學理上稱為獨立機關", "為確保特定公共事務之遂行，並使其運作更具效率及彈性，而依法律設立之組織，且具公法人 屬性，稱為行政法人 51060"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
