  ('aboriginal-7c9828ae-moex-00114', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '依公務人員保障法規定，下列敘述何者正確？', '["該法於受有俸給之文武職公務人員，及其他公營事業機關服務人員，均有適用", "公務人員提起之復審、申訴、再申訴事件，由公務人員保障暨培訓委員會審議決定之", "非現職公務人員基於其原公務人員身分之請求權遭受原服務機關侵害時，亦得提起復審", "公務人員離職後接獲原服務機關之處置者，如認為其不當，不得循申訴、再申訴，僅能提起行 政訴訟救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00115', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-112-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '公務人員對於其服務機關所為之人事行政行為，下列何者不得提起救濟？', '["依積分高低順序或資格條件造列名冊", "核發考績乙等通知書", "申誡處分", "追繳退休金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:55+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL)
